// FIFA 2026 World Cup Third-Place Combinations
// All C(12,8) = 495 combinations
//
// When 8 third-place teams qualify (from 12 possible), this table determines
// which third-place team each group winner plays in the Round of 32.
//
// Group winners that play third-place teams:
// 1A, 1B, 1D, 1E, 1G, 1I, 1K, 1L
//
// The other R32 matches are fixed:
// - R32-1: 2A vs 2B
// - R32-3: 1F vs 2C
// - R32-4: 1C vs 2F
// - R32-6: 2E vs 2I
// - R32-11: 2K vs 2L
// - R32-12: 1H vs 2J
// - R32-14: 1J vs 2H
// - R32-16: 2D vs 2G

export interface ThirdPlaceCombination {
  id: number
  /** 8 groups whose third-place teams qualify (sorted alphabetically) */
  groups: string[]
  /** Maps each group winner (A,B,D,E,G,I,K,L) to the third-place group they play */
  assignments: {
    A: string
    B: string
    D: string
    E: string
    G: string
    I: string
    K: string
    L: string
  }
}

